mapper.select:
select cuv.id, cuv.create_time, cuv.user_id, cuv.merchant_id, cuv.operator_id, cuv.verified_state,
       cuv.update_time, cuv.remarks, su.phone, cuv.name_last_char as username
from cm_user_verified cuv
left join cm_customer su on cuv.user_id = su.user_id
where cuv.deleted = '0'

	and cuv.merchant_id = #{vo.merchantId}


	and cuv.verified_state = #{vo.verifiedState}


	and su.phone = #{vo.phone}

order by cuv.update_time desc
